    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    has_letter = False
    for char in s:
        if char.isalpha():
            has_letter = True
            break

    if not has_letter:
        return s[::-1]

    result = []
    for char in s:
